let input = {};
try { input = $input.item.json; } catch(e) {}
try { if (!input || !input.businessName) input = $json; } catch(e) {}

const projectType = input.projectType || 'landing_page';
const businessName = input.businessName || 'My Business';
const languages = input.languages || ['hu'];
const description = input.description || '';
const designStyle = input.designStyle || 'modern';
const aiModel = input.aiModel || 'deepseek-v4-flash';
const customPrompt = input.customPrompt || '';
const apiKeyOverride = input.apiKeyOverride || '';
const notifyEmail = input.notifyEmail || '';
const logoMode = input.logoMode || 'upload';
const logoPrompt = input.logoPrompt || '';
const colors = input.colors || { primary: '#6366f1', secondary: '#8b5cf6', accent: '#f59e0b', headerBg: '#ffffff' };
const headerLogo = input.headerLogo || null;
const footerLogo = input.footerLogo || null;
const header = input.header || [];
const footer = input.footer || [];
const hero = input.hero || { enabled: true, height: 600 };

let pages = input.pages || [];
if (pages.length > 0 && typeof pages[0] === 'string') {
  pages = pages.map(p => ({ name: p, slug: p.toLowerCase(), description: '', subpages: [] }));
}

// Típusfüggő oldalak, ha nincs megadva
if (pages.length === 0) {
  if (projectType === 'corporate' || projectType === 'blog' || projectType === 'portfolio') {
    pages = [
      { name: 'Kezdőlap', slug: 'home', description: 'Főoldal', subpages: [] },
      { name: 'Rólunk', slug: 'about', description: 'Cégbemutató', subpages: [] },
      { name: 'Szolgáltatások', slug: 'services', description: 'Szolgáltatások', subpages: [] },
      { name: 'Kapcsolat', slug: 'contact', description: 'Elérhetőségek', subpages: [] }
    ];
  } else if (projectType === 'shop') {
    pages = [
      { name: 'Kezdőlap', slug: 'home', description: 'Főoldal', subpages: [] },
      { name: 'Termékek', slug: 'products', description: 'Termékkatalógus', subpages: [] },
      { name: 'Kosár', slug: 'cart', description: 'Bevásárlókosár', subpages: [] },
      { name: 'Kapcsolat', slug: 'contact', description: 'Elérhetőségek', subpages: [] }
    ];
  } else {
    pages = [
      { name: 'Kezdőlap', slug: 'home', description: 'Főoldal', subpages: [] },
      { name: 'Rólunk', slug: 'about', description: 'Cégbemutató', subpages: [] },
      { name: 'Kapcsolat', slug: 'contact', description: 'Elérhetőségek', subpages: [] }
    ];
  }
}

return { businessName, projectType, languages, description, designStyle, aiModel, customPrompt, apiKeyOverride, notifyEmail, logoMode, logoPrompt, colors, headerLogo, footerLogo, header, hero, footer, pages };

const https = require('https');

const data = $input.all()[0].json;
const lang = data.languages[0] || 'hu';

const pageList = data.pages.map(p => {
  let line = p.name + ' (' + p.slug + ')';
  if (p.description) line += ': ' + p.description;
  return line;
}).join('\n');

const heroInfo = data.hero && data.hero.enabled ? `Hero section: yes, height ${data.hero.height}px.` : 'Hero section: no.';

// Egyszerű, strukturált prompt – a válasz JSON lesz a response_format miatt
const base = `Generate a complete website structure as JSON for:

Business: ${data.businessName}
Type: ${data.projectType}
Language: ${lang}
Design: ${data.designStyle}
Description: ${data.description}
Colors: primary=${data.colors.primary}, secondary=${data.colors.secondary}, accent=${data.colors.accent}
${heroInfo}

Required pages:
${pageList}

Output a JSON object with these top-level keys:
- "pages": object where each key is a page slug. Each page has: title, content (with hero if home page, and sections array with type, title, content), meta (title, description)
- "config": system (site_name, language), theme (colors, fonts), header, footer, plugins (array of plugin names)
- "admin_structure": blueprints and forms

Create professional, SEO-optimized content. Write in ${lang} language.`;

const prompt = data.customPrompt ? base + '\n\nCustom requirements: ' + data.customPrompt : base;
const apiKey = data.apiKeyOverride || $env.DEEPSEEK_API_KEY || '';

if (!apiKey) throw new Error('Missing API key');

const requestBody = JSON.stringify({
  model: data.aiModel,
  messages: [
    { role: 'system', content: 'You are a Gravity CMS developer. Respond with pure JSON (no markdown fences).' },
    { role: 'user', content: prompt }
  ],
  temperature: 0.7,
  max_tokens: 4096,
  response_format: { type: 'json_object' }
});

const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.deepseek.com', port: 443, path: '/v1/chat/completions', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey, 'Content-Length': Buffer.byteLength(requestBody) },
    timeout: 120000
  }, (res) => {
    let body = '';
    res.on('data', chunk => body += chunk);
    res.on('end', () => {
      try { const json = JSON.parse(body); if (json.error) reject(new Error(json.error.message)); else resolve(json); }
      catch (e) { reject(new Error('API parse error: ' + body.substring(0, 200))); }
    });
  });
  req.on('error', reject);
  req.on('timeout', () => { req.destroy(); reject(new Error('Timeout')); });
  req.write(requestBody); req.end();
});

return { ...result, _businessName: data.businessName, _pageCount: data.pages.length };

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const response = $input.all()[0].json;

let content;
let rawText = '';
if (response.choices) {
  rawText = response.choices[0].message.content;
  try {
    let jsonStr = rawText.trim();
    // Többlépcsős tisztítás
    if (jsonStr.startsWith('```json')) jsonStr = jsonStr.replace(/^```json\s*/, '').replace(/\s*```$/, '');
    else if (jsonStr.startsWith('```')) jsonStr = jsonStr.replace(/^```\s*/, '').replace(/\s*```$/, '');
    if (!jsonStr.startsWith('{') && jsonStr.includes('{')) {
      jsonStr = jsonStr.substring(jsonStr.indexOf('{'), jsonStr.lastIndexOf('}') + 1);
    }
    content = JSON.parse(jsonStr);
  } catch (e) {
    // Próbáljuk újra regex-szel
    try {
      const m = rawText.match(/\{[\s\S]*\}/);
      if (m) content = JSON.parse(m[0]);
      else throw e;
    } catch (e2) {
      content = { error: "Parse failed after retry", raw: rawText.substring(0, 2000) };
    }
  }
} else {
  content = { error: "No response", apiResponse: response };
  rawText = JSON.stringify(response);
}

const bizName = response._businessName || 'unknown';
const safeName = bizName.toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 30);
const ts = new Date().toISOString().replace(/[:.]/g, '-');

// JSON mentés
const outputDir = '/home/node/output';
const jsonFile = path.join(outputDir, safeName + '_' + ts + '.json');
try { if (!fs.existsSync(outputDir)) fs.mkdirSync(outputDir, { recursive: true }); fs.writeFileSync(jsonFile, JSON.stringify(content, null, 2), 'utf8'); } catch (err) {}

// Verziókövetés
const versionsDir = path.join(outputDir, 'versions');
try { if (!fs.existsSync(versionsDir)) fs.mkdirSync(versionsDir, { recursive: true }); fs.writeFileSync(path.join(versionsDir, safeName + '_' + ts + '.json'), JSON.stringify(content, null, 2), 'utf8'); } catch (err) {}

// SVG logó
let svgSaved = null;
if (content.config && content.config.logo && content.config.logo.svg) {
  const svgDir = path.join(outputDir, 'logos');
  const svgFile = path.join(svgDir, safeName + '_logo.svg');
  try { if (!fs.existsSync(svgDir)) fs.mkdirSync(svgDir, { recursive: true }); fs.writeFileSync(svgFile, content.config.logo.svg, 'utf8'); svgSaved = '/output/logos/' + safeName + '_logo.svg'; } catch (err) {}
}

// GRAVITY CMS DEPLOY – MINDIG!
const gravPagesDir = '/home/node/gravity-pages';
const pageDir = path.join(gravPagesDir, '01.' + safeName);
try {
  if (!fs.existsSync(pageDir)) fs.mkdirSync(pageDir, { recursive: true });

  if (content.pages) {
    Object.keys(content.pages).forEach(slug => {
      const page = content.pages[slug];
      const mdName = slug === 'home' ? 'default.md' : slug + '.md';
      let md = '---\ntitle: "' + (page.title || slug) + '"\n';
      if (page.meta) md += 'metadata:\n  description: "' + (page.meta.description || '') + '"\n';
      md += 'visible: true\n---\n\n';
      if (page.content && page.content.hero) {
        md += '# ' + (page.content.hero.title || '') + '\n\n' + (page.content.hero.subtitle || '') + '\n\n';
      }
      if (page.content && page.content.sections) {
        page.content.sections.forEach(sec => {
          md += '## ' + (sec.title || '') + '\n\n' + (sec.content || '') + '\n\n';
        });
      }
      const mdPath = path.join(pageDir, mdName);
      fs.writeFileSync(mdPath, md, 'utf8');
      try { fs.chmodSync(mdPath, 0o666); } catch (err) {}
    });
  } else {
    let rawMd = '---\ntitle: "' + bizName + '"\nvisible: true\n---\n\n# ' + bizName + '\n\n> Parse failed. Raw response:\n\n' + rawText;
    const mdPath = path.join(pageDir, 'default.md');
    fs.writeFileSync(mdPath, rawMd, 'utf8');
    try { fs.chmodSync(mdPath, 0o666); } catch (err) {}
  }
  // Jogosultságok a teljes könyvtárra
  try { execSync('chmod -R 777 ' + gravPagesDir, { timeout: 2000 }); } catch (err) {}
} catch (err) {}

// Teljes export YAML
function generateFullExportYAML(content) {
  let yaml = '# n8n-gravity v1.3.0 – Generated Gravity CMS Package\n';
  yaml += '# ============================================\n';
  yaml += '# Full export: pages, config, theme, plugins\n\n';
  yaml += '## SYSTEM\n';
  if (content.config && content.config.system) {
    const sys = content.config.system;
    yaml += 'system.yaml:\n';
    if (sys.site_name) yaml += '  site_name: "' + sys.site_name + '"\n';
    yaml += '  timezone: Europe/Budapest\n';
  }
  yaml += '\n## THEME\n';
  if (content.config && content.config.theme && content.config.theme.colors) {
    yaml += 'theme.yaml:\n';
    const th = content.config.theme;
    Object.keys(th.colors).forEach(c => { yaml += '  ' + c + ': "' + th.colors[c] + '"\n'; });
  }
  yaml += '\n## PLUGINS\n';
  if (content.config && content.config.plugins) {
    content.config.plugins.forEach(p => { yaml += '- ' + p + '\n'; });
  } else { yaml += '(none suggested)\n'; }
  yaml += '\n## PAGES (generated as .md files)\n';
  if (content.pages) {
    yaml += Object.keys(content.pages).length + ' pages generated.\n';
    Object.keys(content.pages).forEach(s => {
      const p = content.pages[s];
      yaml += '  - ' + s + (p.title ? ': ' + p.title : '') + '\n';
    });
  } else { yaml += 'Parse failed – no pages generated.\n'; }
  return yaml;
}

if (content.config) {
  const exportYaml = generateFullExportYAML(content);
  const exportFile = path.join(outputDir, safeName + '_' + ts + '_package.txt');
  try { fs.writeFileSync(exportFile, exportYaml, 'utf8'); } catch (err) {}
}

return {
  generated: content,
  saved_to: jsonFile,
  gravity_deployed: true,
  gravity_path: '01.' + safeName,
  pages_count: content.pages ? Object.keys(content.pages).length : 0,
  timestamp: new Date().toISOString(),
  model: response.model || 'deepseek-v4-flash',
  usage: response.usage || {}
};
